WITH target AS (
  SELECT
    c.id AS candidato_id,
    seed.*,
    (
      SELECT hp.id
      FROM historico_politico hp
      WHERE hp.candidato_id = c.id
        AND hp.tipo_evento = 'mandato'
        AND UPPER(COALESCE(hp.estado, '')) = 'AL'
        AND (hp.cargo ILIKE '%Governador%' OR hp.cargo_canonico = 'Governador')
        AND COALESCE(hp.periodo_inicio, 9999) <= EXTRACT(YEAR FROM seed.data_norma::date)::int
        AND COALESCE(hp.periodo_fim, 9999) >= EXTRACT(YEAR FROM seed.data_norma::date)::int
      ORDER BY hp.periodo_inicio DESC NULLS LAST, hp.id
      LIMIT 1
    ) AS historico_politico_id
  FROM candidatos c
  CROSS JOIN _seed_renan_filho_al_sapl_doc_retry seed
  WHERE c.slug = 'renan-filho' AND c.publicavel = true
)
INSERT INTO legislacao_mandato_executivo (
  candidato_id, historico_politico_id, tipo_relacao, esfera, uf_norma, tipo_norma, numero, ano,
  data_norma, ementa, signatario, autoridade_papel, fonte_primaria_url, fonte_primaria_titulo,
  fonte_tramitacao_url, identificador_fonte, metadata
)
SELECT
  target.candidato_id, target.historico_politico_id, target.tipo_relacao, target.esfera, target.uf_norma,
  target.tipo_norma, target.numero, target.ano, target.data_norma::date, target.ementa, target.signatario,
  target.autoridade_papel, target.fonte_primaria_url, target.fonte_primaria_titulo, target.fonte_tramitacao_url,
  target.identificador_fonte, target.metadata
FROM target
WHERE target.historico_politico_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1 FROM legislacao_mandato_executivo lme
    WHERE lme.candidato_id = target.candidato_id
      AND lme.identificador_fonte = target.identificador_fonte
  );

DO $$
DECLARE
  renan_id uuid;
  scope_count int;
BEGIN
  SELECT id INTO renan_id FROM candidatos WHERE slug = 'renan-filho' AND publicavel = true;
  SELECT count(*) INTO scope_count
  FROM legislacao_mandato_executivo
  WHERE candidato_id = renan_id
    AND metadata ->> 'coverage_id' = 'renan-filho-al-sapl-pdfs-assinados-2015-2022-20260703';
  IF scope_count <> 698 THEN
    RAISE EXCEPTION 'renan-filho LME SAPL total esperado 698, encontrado %', scope_count;
  END IF;
END $$;
